/**
 * Sanitizes AI output to ensure valid JSON is parsed
 * even if the model included Markdown, preamble, or trailing text.
 */

// Get the raw output from the previous node
let rawOutput = $input.first().json.output || "";

try {
  // 1. Find the start of either an Object { or an Array [
  const startBrace = rawOutput.indexOf('{');
  const startBracket = rawOutput.indexOf('[');

  // Determine which one comes first (ignoring -1)
  let start = -1;
  if (startBrace !== -1 && (startBracket === -1 || startBrace < startBracket)) {
    start = startBrace;
  } else {
    start = startBracket;
  }

  // 2. Find the corresponding last closing character
  const endBrace = rawOutput.lastIndexOf('}');
  const endBracket = rawOutput.lastIndexOf(']');
  const end = Math.max(endBrace, endBracket) + 1;

  if (start === -1 || end <= 0) {
    throw new Error("No JSON structure ({} or []) found in AI output");
  }

  // 3. Extract and trim
  const cleanJsonString = rawOutput.substring(start, end).trim();

  // 4. Parse the cleaned string
  const parsed = JSON.parse(cleanJsonString);

  // 5. Return the parsed object
  return (Array.isArray(parsed)) ? { data: parsed } : parsed;

} catch (error) {
  return {
    error: "Failed to parse AI output",
    original_output: rawOutput,
    details: error.message,
    ai_hard_failure: true
  };
}

var config = {...$input.first().json.order_config}

var cleanData = {}

for (const key in config){
  delete config[key].validation_logic
  delete config[key].visibility_rule
  delete config[key].option_prices 
  delete config[key].option_labels
  delete config[key].constraints
  for (const value in config[key])
    {
      if(config[key][value] == null){
        return {value: config[key]}

      }
    }
  cleanData = Object.fromEntries(
  Object.entries(config).filter(([_, value]) => value !== null  )
);

}
return {order_config:cleanData}
